// Create an IntersectionObserver to detect when stats are in view
const statsObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    if (entry.isIntersecting) {
      // Get the stats section
      const statsSection = entry.target;

      // Get all stat value elements
      const statElements = [
        statsSection.querySelector('#stat_1_value'),
        statsSection.querySelector('#stat_2_value'),
        statsSection.querySelector('#stat_3_value'),
        statsSection.querySelector('#stat_4_value'),
        statsSection.querySelector('#stat_5_value'),
        statsSection.querySelector('#stat_6_value')
      ];

      // Get the stats data
      const statsData = {
        revenueIncrease: '+300%',
        supportTime: '5×',
        studentRetention: '+85%',
        avgTicket: '+70%',
        satisfaction: '98%',
        churnRate: '-65%'
      };

      const statValues = [
        statsData.revenueIncrease,
        statsData.supportTime,
        statsData.studentRetention,
        statsData.avgTicket,
        statsData.satisfaction,
        statsData.churnRate
      ];

      // Animate each stat with a slight delay between them
      statElements.forEach((element, index) => {
        if (element) {
          setTimeout(() => {
            animateValue(element, 0, statValues[index], 2000);
          }, index * 200); // 200ms delay between each animation
        }
      });

      // Disconnect the observer after animation is triggered
      statsObserver.disconnect();
    }
  });
}, { threshold: 0.25 }); // Trigger when at least 25% of the element is visible

// Function to animate counting up
function animateValue(obj, start, end, duration) {
  if (!obj) return;

  // Parse the end value
  let prefix = '';
  let suffix = '';
  let numericEnd = 0;

  if (typeof end === 'string') {
    // Handle percentage values with + or - prefix
    if (end.includes('%')) {
      numericEnd = parseInt(end.replace(/[^0-9]/g, ''));
      prefix = end.startsWith('+') ? '+' : (end.startsWith('-') ? '-' : '');
      suffix = '%';
    } 
    // Handle multiplier values (×)
    else if (end.includes('×')) {
      numericEnd = parseInt(end.replace(/[^0-9]/g, ''));
      suffix = '×';
    }
    // Handle other formats
    else {
      numericEnd = parseInt(end.replace(/[^0-9]/g, ''));
      if (end.startsWith('+')) prefix = '+';
      if (end.startsWith('-')) prefix = '-';
    }
  } else {
    numericEnd = end;
  }

  let startTimestamp = null;
  const step = (timestamp) => {
    if (!startTimestamp) startTimestamp = timestamp;
    const progress = Math.min((timestamp - startTimestamp) / duration, 1);

    const current = Math.floor(progress * numericEnd);
    obj.innerHTML = prefix + current + suffix;

    if (progress < 1) {
      window.requestAnimationFrame(step);
    } else {
      // Ensure final value is exactly as specified
      obj.innerHTML = end;
    }
  };

  window.requestAnimationFrame(step);
}

