// Create a map to track which elements have been animated
const animatedMap = new Map();

// Create an IntersectionObserver to detect when elements enter the viewport
const animationObserver = new IntersectionObserver((entries) => {
  entries.forEach(entry => {
    const element = entry.target;
    const elementData = animatedMap.get(element);

    // If element is in view and hasn't been animated yet
    if (entry.isIntersecting && elementData && !elementData.animated) {
      // Mark as animated
      elementData.animated = true;

      // Apply animation with the original delay
      setTimeout(() => {
        element.style.opacity = '1';
        element.style.transform = 'translateY(0)';
      }, parseInt(elementData.originalDelay) || 0);

      // Stop observing this element
      animationObserver.unobserve(element);
    }
  });
}, { 
  threshold: 0.15, // Trigger when at least 15% of the element is visible
  rootMargin: '0px 0px -10% 0px' // Trigger slightly before the element is fully in view
});

// Get all elements with animations
const animatedElements = Array.from(wwLib.getFrontDocument().querySelectorAll('[style*="animationKeyframes"]'));

// Initialize all animated elements
animatedElements.forEach(element => {
  // Skip elements in the hero section (they should animate immediately)
  const isInHeroSection = element.closest('[name="Hero Section"]') !== null;

  // Skip elements in the stats section (they're handled by another script)
  const isInStatsSection = element.closest('#stats_section') !== null;

  if (isInHeroSection || isInStatsSection) return;

  // Extract original animation delay
  const originalDelay = element.style.animationDelay || '0ms';
  const delayMs = parseInt(originalDelay) || 0;

  // Set initial state - hidden and translated down
  element.style.opacity = '0';
  element.style.transform = 'translateY(20px)';
  element.style.transition = 'opacity 0.8s ease, transform 0.8s ease';

  // Store the element in our map
  animatedMap.set(element, {
    animated: false,
    originalDelay: delayMs
  });

  // Start observing this element
  animationObserver.observe(element);
});

// Clean up on page unload
return () => {
  if (animationObserver) {
    animationObserver.disconnect();
  }
};
